#[test]
fn unequal_cols_requires_width_on_each_col() {
    let body = r#"<w:p><w:r><w:t>Two unequal columns.</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/><w:cols w:num="2" w:equalWidth="false"><w:col w:w="4000" w:space="720"/><w:col w:w="6800"/></w:cols></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.212 (ISO §17.6.3 / §17.6.4): with equalWidth=false each col carries w and num matches the two col children, satisfying Word's requirement; the document opens clean",
    );
}

#[test]
fn lnnumtype_countby_above_word_max_opens_clean() {
    let body = r#"<w:p><w:pPr><w:sectPr><w:type w:val="continuous"/><w:pgSz w:w="12240" w:h="15840"/><w:lnNumType w:countBy="500" w:restart="newSection"/></w:sectPr></w:pPr><w:r><w:t>Numbered lines section.</w:t></w:r></w:p><w:p><w:r><w:t>Following section.</w:t></w:r></w:p><w:sectPr><w:pgSz w:w="12240" w:h="15840"/></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.215 (ISO §17.6.8): Word clamps an out-of-range lnNumType@countBy (1..=100) on load rather than rejecting the file; combined with §17.6.22 allowing lnNumType on continuous breaks, the document opens clean",
    );
}

#[test]
fn lone_continuous_section_no_predecessor_keeps_own_geometry() {
    let body = r#"<w:p><w:r><w:t>Only</w:t></w:r></w:p><w:sectPr><w:type w:val="continuous"/><w:pgSz w:w="15840" w:h="12240" w:orient="landscape"/><w:pgMar w:top="1440" w:right="1440" w:bottom="1440" w:left="1440"/></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.6.22: a lone continuous section is well-formed; continuous inheritance is a no-op with no predecessor and the document opens clean",
    );
}

#[test]
fn continuous_section_does_not_fabricate_geometry_when_predecessor_also_omits() {
    let body = r#"<w:p><w:pPr><w:sectPr><w:type w:val="nextPage"/><w:pgMar w:top="720" w:right="720" w:bottom="720" w:left="720"/></w:sectPr></w:pPr><w:r><w:t>First</w:t></w:r></w:p><w:p><w:r><w:t>Second</w:t></w:r></w:p><w:sectPr><w:type w:val="continuous"/><w:pgMar w:top="720" w:right="720" w:bottom="720" w:left="720"/></w:sectPr>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ISO 29500-1 §17.6.18 / §17.6.22: two sections that both omit pgSz are well-formed and open clean; continuous inheritance must not fabricate a pgSz with no source value to copy",
    );
}

#[ignore = "open question: same \"\\n\\n\" paragraph-join separator plus to_text() surfaces w:footnoteReference as U+FFFC anchor placeholder — read-view modeling question, needs adjudication (§17.18.77 / §17.6.22 / §17.11.14)"]
#[test]
fn continuous_break_with_footnote_ref_is_layout_only() {
    let body = r#"<w:p><w:r><w:t>First section paragraph.</w:t></w:r><w:r><w:footnoteReference w:id="2"/></w:r><w:pPr><w:sectPr><w:type w:val="continuous"/></w:sectPr></w:pPr></w:p><w:p><w:r><w:t>Second section paragraph.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let doc = Document::parse(&b).expect("parse");
    let accept = doc.read_accepted().unwrap().to_text();
    assert_eq!(
        accept.trim(),
        "First section paragraph.Second section paragraph.",
        "ISO 29500-1 §17.18.77 / §17.6.22 / §17.11.14: a continuous break (even with a same-page footnote ref) is layout-only; accept-all must reproduce both paragraphs' prose verbatim and the footnoteReference anchor must add no characters"
    );

    let reject = doc.read_rejected().unwrap().to_text();
    assert_eq!(
        reject.trim(),
        "First section paragraph.Second section paragraph.",
        "ISO 29500-1 §17.18.77: there are no tracked changes; reject-all must reproduce the identical layout-only text, confirming the section mark and footnote anchor are zero-width"
    );
}
